 1	import React, { ChangeEvent, Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { V1CPU } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import {
 5	  CPUComponent,
 6	  getUpdatedCPU,
 7	} from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/utils/utils';
 8	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 9	import { Grid, GridItem, NumberInput, Text } from '@patternfly/react-core';
10	
11	import './VCPUInput.scss';
12	
13	type vCPUInputProps = {
14	  cpu: V1CPU;
15	  isDisabled: boolean;
16	  setCPU: Dispatch<SetStateAction<V1CPU>>;
17	};
18	
19	const VCPUInput: FC<vCPUInputProps> = ({ cpu, isDisabled, setCPU }) => {
20	  const { t } = useKubevirtTranslation();
21	
22	  const handleButtonInput = (newCPU: V1CPU) => {
23	    setCPU(newCPU);
24	  };
25	
26	  return (
27	    <Grid className="vcpu-input" hasGutter>
28	      <GridItem span={3}>
29	        <Text disabled={isDisabled}>{t('vCPU')}</Text>
30	      </GridItem>
31	      <GridItem span={9}>
32	        <NumberInput
33	          onChange={(e: ChangeEvent<HTMLInputElement>) => {
34	            const newNumber = +e?.target?.value;
35	            setCPU(getUpdatedCPU(cpu, newNumber, CPUComponent.sockets));
36	          }}
37	          onMinus={() =>
38	            handleButtonInput(getUpdatedCPU(cpu, +cpu?.sockets - 1, CPUComponent.sockets))
39	          }
40	          onPlus={() =>
41	            handleButtonInput(getUpdatedCPU(cpu, +cpu?.sockets + 1, CPUComponent.sockets))
42	          }
43	          inputName="cpu-input"
44	          isDisabled={isDisabled}
45	          min={1}
46	          value={cpu?.sockets}
47	        />
48	      </GridItem>
49	    </Grid>
50	  );
51	};
52	
53	export default VCPUInput;

